import { Link } from "react-router-dom";

import React, { useEffect, useState } from "react";

import { getAllVariants } from "../services/ApiService";

import cretaImage from "../assets/creta.jpg";
import venueImage from "../assets/venue.jpg";
import i20Image from "../assets/i20.jpg";

function Home() {

    const [variants, setVariants] = useState([]);

    useEffect(() => {

        loadVariants();

    }, []);

    const loadVariants = async () => {

        try {

            const response = await getAllVariants();

            console.log(response.data);

            setVariants(response.data);

        } catch (error) {

            console.log(error);

        }

    };


const getCarImage = (variantName) => {

    if (variantName === "Creta") {
        return cretaImage;
    }

    if (variantName === "Venue") {
        return venueImage;
    }

    if (variantName === "i20") {
        return i20Image;
    }
};

    return (

        <div style={{padding: "20px"}}>

            <h1>All Car Variants</h1>

            {
                variants.map((variant) => (

                    <div
    key={variant.id}

    style={{
        border: "1px solid lightgray",
        borderRadius: "10px",
        padding: "20px",
        marginBottom: "20px",
        width: "300px",
        boxShadow: "0px 0px 10px lightgray"
    }}
>

    <img
        src={getCarImage(variant.variantName)}
        alt="car"

        style={{
            width: "100%",
            height: "200px",
            objectFit: "cover",
            borderRadius: "10px"
        }}
    />

    <h2>
        {variant.variantName}
    </h2>

    <p>
        <b>Company :</b>
        {" "}
        {variant.carCompany.companyName}
    </p>

    <p>
        <b>Fuel Type :</b>
        {" "}
        {variant.fuelType}
    </p>

    <p>
        <b>Price Per Day :</b>
        {" "}
        ₹ {variant.pricePerDay}
    </p>


    <button
        style={{
            padding: "10px",
            backgroundColor: "black",
            color: "white",
            border: "none",
            borderRadius: "5px",
            cursor: "pointer"
        }}
    >

        Book Now

    </button>

</div>
                ))
            }

        </div>
    );
}

export default Home;
